class Solution:
    def singleNumber(self, nums):
        from collections import Counter
        return [v for v, c in Counter(nums).items() if c == 1]

solutions.python:
class Solution:
    def singleNumber(self, nums):
        xor = 0
        for v in nums:
            xor ^= v
        bit = xor & (-xor)
        a = 0
        for v in nums:
            if v & bit:
                a ^= v
        return [a, a ^ xor]

