var singleNumber = function(nums) {
    let xor = 0;
    for (const v of nums) xor ^= v;
    let bit = xor & (-xor);
    let a = 0;
    for (const v of nums) {
        if (v & bit) a ^= v;
    }
    return [a, (a ^ xor)];
};
